    wiringPiI2CWriteReg8(i2c_fd, 0x08, 0x00); // Disable ALS force mode
    wiringPiI2CWriteReg8(i2c_fd, 0x09, 0x00); // Disable PS force mode
    wiringPiI2CWriteReg8(i2c_fd, 0x0A, 0x00); // Disable UV force mode
    wiringPiI2CWriteReg8(i2c_fd, 0x0B, 0x00); // Disable IR force mode

