// Constants
#define LED_GPIO 24
#define BH1750_ADDR 0x23
#define LUX_THRESHOLD 5.0
#define I2C_BUS 1

// Global variables
int i2c_handle;
FILE *log_file;
double last_logged_lux = -1.0;

// Function prototypes
double read_lux();
void set_led_brightness(int brightness);
void log_lux(double lux);
void signal_handler(int signal);

// Function to read lux value from BH1750 sensor
double read_lux() {
    unsigned char buffer[2];
    double lux;

    int result = i2cReadI2CBlockData(i2c_handle, 0x00, (char *)buffer, 2); // Read 2 bytes from register 0x00

    if (result != 2) {
        fprintf(stderr, "Error reading from I2C: %d\n", result);
        return -1.0; // Indicate error
    }

    lux = (buffer[0] << 8 | buffer[1]) * 0.001; // Combine bytes and convert to lux

    return lux;
}

// Function to set LED brightness using PWM
void set_led_brightness(int brightness) {
    if (brightness < 0) brightness = 0;
    if (brightness > 255) brightness = 255;

    gpioPWM(LED_GPIO, brightness); // Set PWM duty cycle
}

// Function to log lux value to file
void log_lux(double lux) {
    time_t t = time(NULL);
    struct tm tm = *localtime(&t);
    char timestamp[20];
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", &tm);

    if (log_file != NULL) {
        fprintf(log_file, "%s, %.2f\n", timestamp, lux);
        fflush(log_file); // Ensure data is written to disk
    } else {
        fprintf(stderr, "Error: Log file is not open.\n");
    }
}

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    printf("Caught signal %d, cleaning up...\n", signal);
    set_led_brightness(0); // Turn off LED
    if (i2c_handle >= 0) {
        i2cClose(i2c_handle);
    }
    if (log_file != NULL) {
        fclose(log_file);
    }
    gpioTerminate();
    exit(0);
}

int main() {
    double lux;
    int brightness;

    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Set GPIO24 as output
    gpioSetMode(LED_GPIO, PI_OUTPUT);

    // Set PWM range (0-255)
    gpioSetPWMrange(LED_GPIO, 255);

    // Open I2C connection
    i2c_handle = i2cOpen(I2C_BUS, BH1750_ADDR, 0); // Bus 1, address 0x23, no flags
    if (i2c_handle < 0) {
        fprintf(stderr, "Error opening I2C: %d\n", i2c_handle);
        gpioTerminate();
        return 1;
    }

    // Open log file
    log_file = fopen("light_log.txt", "a");
    if (log_file == NULL) {
        fprintf(stderr, "Error opening log file!\n");
        i2cClose(i2c_handle);
        gpioTerminate();
        return 1;
    }

    // Register signal handler
    signal(SIGINT, signal_handler);

    printf("Light control program started. Press Ctrl+C to exit.\n");

    while (1) {
        lux = read_lux();

        if (lux >= 0) {
            if (lux > 0) {
                brightness = (int)(lux / 10); // Map lux to brightness (0-255)
                if (brightness > 255) brightness = 255;
                set_led_brightness(brightness);

                if (lux - last_logged_lux >= LUX_THRESHOLD) {
                    log_lux(lux);
                    last_logged_lux = lux;
                }
            } else {
                set_led_brightness(0);
            }
        } else {
            fprintf(stderr, "Error reading lux value.\n");
        }

        gpioDelay(100); // Delay for 100 milliseconds
    }

    // The program should not reach here due to the infinite loop,
    // but include cleanup code for completeness.
    i2cClose(i2c_handle);
    fclose(log_file);
    gpioTerminate();
    return 0;
}

